import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const Checkpoint = () => {
  const [checkpoints, setCheckpoints] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const apiUrl = 'http://localhost:5000';

  const fetchCheckpoints = async () => {
    try {
      const res = await fetch(`${apiUrl}/api/checkpoints`);
      if (!res.ok) throw new Error("Failed to fetch data");
      const data = await res.json();
      setCheckpoints(data);
      setError(null);
    } catch (err) {
      console.error('Failed to fetch checkpoints:', err);
      setError('Gagal mengambil data checkpoint');
    }
    setLoading(false);
  };

  useEffect(() => {
    setLoading(true);
    fetchCheckpoints();

    const interval = setInterval(() => {
      fetchCheckpoints();
    }, 2000);  // refresh setiap 2 detik

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="bg-gray-800 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img src="/images/admin.png" alt="Admin Icon" className="rounded-full mb-2" />
            <h2 className="font-semibold text-lg">Admin</h2>
          </div>
          <nav className="space-y-6">
            <Link to="/master-data" className="block bg-gray-700 rounded-lg p-3 text-center">Master Data</Link>
            <Link to="/tracking" className="block bg-gray-700 rounded-lg p-3 text-center">Tracking</Link>
            <Link to="/checkpoint" className="block bg-blue-700 rounded-lg p-3 text-center">Checkpoint</Link>
            <Link to="/info-driver" className="block bg-gray-700 rounded-lg p-3 text-center">Info Driver</Link>
          </nav>
        </div>
        <nav className="space-y-6 mt-6">
          <Link to="/settings" className="block bg-gray-700 rounded-lg p-3 text-center">Settings</Link>
          <Link to="/logout" className="block bg-gray-700 rounded-lg p-3 text-center">Logout</Link>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6">
        <header className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-bold">Dashboard / Checkpoint Logs</h1>
        </header>

        {loading && <div>Loading...</div>}
        {error && <div className="text-red-500 mb-4">{error}</div>}

        <section className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold mb-4">Checkpoint Logs (Auto-refresh 2 detik)</h2>

          <table className="w-full table-auto border-collapse border border-gray-300">
            <thead>
              <tr className="bg-gray-200">
                <th className="border border-gray-300 p-2">Truck ID</th>
                <th className="border border-gray-300 p-2">Truck Type</th>
                <th className="border border-gray-300 p-2">Driver</th>
                <th className="border border-gray-300 p-2">Checkpoint</th>
                <th className="border border-gray-300 p-2">Timestamp</th>
              </tr>
            </thead>
            <tbody>
              {checkpoints.length > 0 ? (
                checkpoints.map((cp) => (
                  <tr key={cp.id}>
                    <td className="border border-gray-300 p-2">{cp.truckId}</td>
                    <td className="border border-gray-300 p-2">{cp.truckType}</td>
                    <td className="border border-gray-300 p-2">{cp.driver}</td>
                    <td className="border border-gray-300 p-2">{cp.checkpoint}</td>
                    <td className="border border-gray-300 p-2">{new Date(cp.timestamp).toLocaleString()}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5" className="text-center p-4">No checkpoint data found</td>
                </tr>
              )}
            </tbody>
          </table>
        </section>
      </main>
    </div>
  );
};

export default Checkpoint;
